@app.route('/batch_contribute', methods=['POST'])
def batch_contribute():
    contributor_id = request.form.get('contributor_id', 'anonymous')
    
    files = request.files.getlist('files')
    labels = request.form.getlist('labels')
    
    if len(files) != len(labels):
        return jsonify({'error': 'Number of files and labels must match'}), 400
    
    added_count = 0
    errors = []
    
    for file, label in zip(files, labels):
        try:
            label = int(label)
            image_data = file.read()
            community_model.add_training_sample(image_data, label, contributor_id)
            added_count += 1
        except Exception as e:
            errors.append({'filename': file.filename, 'error': str(e)})
    
    return jsonify({
        'success': True,
        'added': added_count,
        'errors': errors,
        'total_samples': community_model.metadata['total_samples']
    }), 200

